                minSum = d;
            }
            long otherD = gcd / d;
            if (otherD > 0 && otherD < minSum && remainder % otherD == 0) {
                minSum = otherD;
            }
        }
    }

    return minSum;
}

private static long computeGCD(long a, long b) {
    while (b != 0) {
        long temp = b;
        b = a % b;
        a = temp;
    }
    return a;
